Literal.Value:
'{
  "description": "Vendas por Região — Treemap real (tamanho ∝ receita). Campos: dCliente[REGIAO] + _Medidas[Total Receita]. PROVIDER: Vega (não Vega-Lite).",
  "background": "transparent",
  "padding": 0,
  "autosize": { "type": "none", "contains": "padding" },
  "signals": [
    { "name": "titleH", "value": 48 },
    { "name": "total", "update": "length(data(''totais'')) > 0 ? data(''totais'')[0].sm : 1" }
  ],
  "data": [
    { "name": "dataset" },
    {
      "name": "totais",
      "source": "dataset",
      "transform": [{ "type": "aggregate", "fields": ["Total Receita"], "ops": ["sum"], "as": ["sm"] }]
    },
    {
      "name": "tree",
      "source": "dataset",
      "transform": [
        { "type": "nest", "keys": [] },
        {
          "type": "treemap",
          "field": "Total Receita",
          "sort": { "field": "value", "order": "descending" },
          "round": true,
          "method": "squarify",
          "ratio": 1.5,
          "paddingInner": 6,
          "size": [{ "signal": "width" }, { "signal": "max(height - titleH, 10)" }]
        }
      ]
    },
    {
      "name": "leaves",
      "source": "tree",
      "transform": [{ "type": "filter", "expr": "datum.depth === 1" }]
    }
  ],
  "scales": [
    {
      "name": "op",
      "type": "linear",
      "zero": true,
      "domain": { "data": "leaves", "field": "Total Receita" },
      "range": [0.22, 0.9]
    }
  ],
  "marks": [
    {
      "type": "text",
      "encode": {
        "enter": {
          "x": { "value": 2 }, "y": { "value": 0 },
          "text": { "value": "Vendas por Região" },
          "fill": { "value": "#ffffff" }, "fontSize": { "value": 15 }, "fontWeight": { "value": 600 }, "baseline": { "value": "top" }
        }
      }
    },
    {
      "type": "text",
      "encode": {
        "enter": {
          "x": { "value": 2 }, "y": { "value": 22 },
          "text": { "value": "Participação na receita" },
          "fill": { "value": "#8888A8" }, "fontSize": { "value": 11 }, "baseline": { "value": "top" }
        }
      }
    },
    {
      "type": "rect",
      "from": { "data": "leaves" },
      "encode": {
        "enter": {
          "fill": { "value": "#8B5CF6" },
          "stroke": { "value": "#0E0E20" },
          "strokeWidth": { "value": 3 },
          "cornerRadius": { "value": 8 }
        },
        "update": {
          "x": { "field": "x0" },
          "y": { "signal": "datum.y0 + titleH" },
          "x2": { "field": "x1" },
          "y2": { "signal": "datum.y1 + titleH" },
          "fillOpacity": { "scale": "op", "field": "Total Receita" },
          "tooltip": { "signal": "{''Região'': datum.REGIAO, ''Receita (R$)'': format(datum[''Total Receita''], '',.2f''), ''Participação'': format(datum[''Total Receita'']/total, ''.1%'')}" }
        }
      }
    },
    {
      "type": "text",
      "from": { "data": "leaves" },
      "encode": {
        "enter": { "fill": { "value": "#ffffff" }, "fontSize": { "value": 12 }, "fontWeight": { "value": 600 }, "baseline": { "value": "top" } },
        "update": {
          "x": { "signal": "datum.x0 + 12" },
          "y": { "signal": "datum.y0 + titleH + 11" },
          "text": { "field": "REGIAO" },
          "opacity": { "signal": "(datum.x1 - datum.x0) > 64 && (datum.y1 - datum.y0) > 34 ? 1 : 0" }
        }
      }
    },
    {
      "type": "text",
      "from": { "data": "leaves" },
      "encode": {
        "enter": { "fill": { "value": "#F2EEFE" }, "fontSize": { "value": 14 }, "fontWeight": { "value": 700 }, "baseline": { "value": "top" } },
        "update": {
          "x": { "signal": "datum.x0 + 12" },
          "y": { "signal": "datum.y0 + titleH + 28" },
          "text": { "signal": "''R$ '' + format(datum[''Total Receita'']/1000000, '',.1f'') + '' mi''" },
          "opacity": { "signal": "(datum.x1 - datum.x0) > 70 && (datum.y1 - datum.y0) > 52 ? 1 : 0" }
        }
      }
    },
    {
      "type": "text",
      "from": { "data": "leaves" },
      "encode": {
        "enter": { "fill": { "value": "#C3B4EE" }, "fontSize": { "value": 10.5 }, "baseline": { "value": "top" } },
        "update": {
          "x": { "signal": "datum.x0 + 12" },
          "y": { "signal": "datum.y0 + titleH + 47" },
          "text": { "signal": "format(datum[''Total Receita'']/total, ''.1%'')" },
          "opacity": { "signal": "(datum.x1 - datum.x0) > 70 && (datum.y1 - datum.y0) > 70 ? 1 : 0" }
        }
      }
    }
  ]
}'
